import React, { useState, useEffect } from 'react';
import { v4 as uuidv4 } from 'uuid';

const CLIENT_ID = 'your-client-id';
const REDIRECT_URI = 'your-redirect-uri';
const AUTHORIZATION_ENDPOINT = 'https://authorization-server.com/auth';
const TOKEN_ENDPOINT = 'https://authorization-server.com/token';

const generateCodeVerifier = () => {
  const array = new Uint32Array(56 / 2);
  window.crypto.getRandomValues(array);
  return Array.from(array, dec => ('0' + dec.toString(16)).substr(-2)).join('');
};

const generateCodeChallenge = async (verifier) => {
  const encoder = new TextEncoder();
  const data = encoder.encode(verifier);
  const digest = await window.crypto.subtle.digest('SHA-256', data);
  return btoa(String.fromCharCode(...new Uint8Array(digest)))
    .replace(/\+/g, '-').replace(/\//g, '_').replace(/=+$/, '');
};

const App = () => {
  const [accessToken, setAccessToken] = useState(null);

  useEffect(() => {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const storedVerifier = localStorage.getItem('code_verifier');

    if (code && storedVerifier) {
      fetchAccessToken(code, storedVerifier);
    }
  }, []);

  const fetchAccessToken = async (code, verifier) => {
    try {
      const response = await fetch(TOKEN_ENDPOINT, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: new URLSearchParams({
          client_id: CLIENT_ID,
          grant_type: 'authorization_code',
          code: code,
          redirect_uri: REDIRECT_URI,
          code_verifier: verifier,
        }),
      });

      const data = await response.json();
      if (data.access_token) {
        setAccessToken(data.access_token);
        localStorage.setItem('access_token', data.access_token);
        localStorage.removeItem('code_verifier');
      }
    } catch (error) {
      console.error('Error fetching access token:', error);
    }
  };

  const handleLogin = async () => {
    const codeVerifier = generateCodeVerifier();
    const codeChallenge = await generateCodeChallenge(codeVerifier);
    localStorage.setItem('code_verifier', codeVerifier);

    const state = uuidv4();
    const authUrl = `${AUTHORIZATION_ENDPOINT}?response_type=code&client_id=${CLIENT_ID}&redirect_uri=${encodeURIComponent(REDIRECT_URI)}&code_challenge=${codeChallenge}&code_challenge_method=S256&state=${state}`;

    window.location.href = authUrl;
  };

  return (
    <div>
      {!accessToken ? (
        <button onClick={handleLogin}>Login with OAuth</button>
      ) : (
        <div>Authenticated! Access Token: {accessToken}</div>
      )}
    </div>
  );
};

export default App;